import { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import API from '../services/axios';

const CATEGORIES = ['All', 'Concert', 'Conference', 'Workshop', 'Sports', 'Exhibition', 'Festival', 'Comedy', 'Theatre', 'Other'];

function Home() {
  const [events, setEvents] = useState([]);
  const [filtered, setFiltered] = useState([]);
  const [search, setSearch] = useState('');
  const [location, setLocation] = useState('');
  const [category, setCategory] = useState('All');
  const [loading, setLoading] = useState(true);
  const navigate = useNavigate();

  useEffect(() => { fetchEvents(); }, []);

  useEffect(() => {
    let result = events;
    if (search) result = result.filter(e => e.name.toLowerCase().includes(search.toLowerCase()));
    if (location) result = result.filter(e => e.venue.toLowerCase().includes(location.toLowerCase()));
    if (category !== 'All') result = result.filter(e => e.category === category);
    setFiltered(result);
  }, [search, location, category, events]);

  const fetchEvents = async () => {
    try {
      const res = await API.get('/events');
      setEvents(res.data.events || []);
      setFiltered(res.data.events || []);
    } catch { console.error('Failed to fetch events'); }
    finally { setLoading(false); }
  };

  return (
    <div style={{ minHeight: '100vh' }}>

      {/* HERO */}
      <section style={{
        background: 'linear-gradient(135deg, #1e1b4b 0%, #312e81 40%, #4c1d95 100%)',
        padding: '5rem 2rem 4rem', position: 'relative', overflow: 'hidden'
      }}>
        {/* Background decoration */}
        <div style={{
          position: 'absolute', top: '-100px', right: '-100px',
          width: '500px', height: '500px', borderRadius: '50%',
          background: 'radial-gradient(circle, rgba(167,139,250,0.15) 0%, transparent 70%)',
          pointerEvents: 'none'
        }} />
        <div style={{
          position: 'absolute', bottom: '-50px', left: '-50px',
          width: '300px', height: '300px', borderRadius: '50%',
          background: 'radial-gradient(circle, rgba(124,58,237,0.2) 0%, transparent 70%)',
          pointerEvents: 'none'
        }} />

        <div style={{ maxWidth: '900px', margin: '0 auto', textAlign: 'center', position: 'relative' }}>
          <p style={{ color: '#a78bfa', fontSize: '0.85rem', fontWeight: '600', letterSpacing: '3px', marginBottom: '1rem', textTransform: 'uppercase' }}>
            Find Your Next Experience
          </p>
          <h1 style={{
            fontSize: 'clamp(2.5rem, 5vw, 4rem)', fontWeight: '800',
            color: 'white', lineHeight: '1.15', marginBottom: '1.5rem'
          }}>
            Discover & Promote<br />
            <span style={{ color: '#a78bfa' }}>Upcoming Event</span>
          </h1>

          {/* Search Bar */}
          <div style={{
            background: 'rgba(255,255,255,0.08)', backdropFilter: 'blur(20px)',
            border: '1px solid rgba(255,255,255,0.15)', borderRadius: '16px',
            padding: '1rem 1.5rem', display: 'flex', gap: '1rem', alignItems: 'center',
            maxWidth: '700px', margin: '0 auto', flexWrap: 'wrap'
          }}>
            <div style={{ flex: 1, minWidth: '150px', display: 'flex', alignItems: 'center', gap: '8px' }}>
              <span style={{ color: '#a78bfa', fontSize: '1rem' }}>🔍</span>
              <input
                type="text" placeholder="Search Event..."
                value={search} onChange={(e) => setSearch(e.target.value)}
                style={{
                  background: 'transparent', border: 'none', outline: 'none',
                  color: 'white', fontSize: '0.9rem', width: '100%',
                }}
              />
            </div>
            <div style={{ width: '1px', height: '30px', background: 'rgba(255,255,255,0.2)' }} />
            <div style={{ flex: 1, minWidth: '150px', display: 'flex', alignItems: 'center', gap: '8px' }}>
              <span style={{ color: '#a78bfa' }}>📍</span>
              <input
                type="text" placeholder="Search Location..."
                value={location} onChange={(e) => setLocation(e.target.value)}
                style={{
                  background: 'transparent', border: 'none', outline: 'none',
                  color: 'white', fontSize: '0.9rem', width: '100%',
                }}
              />
            </div>
            <div style={{ width: '1px', height: '30px', background: 'rgba(255,255,255,0.2)' }} />
            <select
              value={category} onChange={(e) => setCategory(e.target.value)}
              style={{
                background: 'transparent', border: 'none', outline: 'none',
                color: 'white', fontSize: '0.85rem', cursor: 'pointer',
              }}
            >
              {CATEGORIES.map(c => <option key={c} value={c} style={{ background: '#312e81' }}>{c}</option>)}
            </select>
            <div style={{ width: '1px', height: '30px', background: 'rgba(255,255,255,0.2)' }} />
            <button style={{
              background: 'linear-gradient(135deg, #7c3aed, #a78bfa)',
              color: 'white', border: 'none', padding: '10px 24px',
              borderRadius: '10px', cursor: 'pointer', fontWeight: '600',
              fontSize: '0.85rem', whiteSpace: 'nowrap'
            }}>Create Event</button>
          </div>
        </div>
      </section>

      {/* EVENTS SECTION */}
      <section style={{
        background: 'linear-gradient(135deg, #1e1b4b 0%, #312e81 100%)',
        padding: '3rem 2rem', minHeight: '60vh'
      }}>
        <div style={{ maxWidth: '1400px', margin: '0 auto' }}>
          <h2 style={{ color: 'white', fontSize: '1.5rem', fontWeight: '700', marginBottom: '2rem' }}>
            Upcoming Events
            <span style={{ color: '#a78bfa', fontSize: '1rem', fontWeight: '400', marginLeft: '10px' }}>({filtered.length})</span>
          </h2>

          {loading ? (
            <div style={{ textAlign: 'center', padding: '4rem', color: 'rgba(255,255,255,0.5)' }}>
              <div style={{ fontSize: '3rem', marginBottom: '1rem' }}>🎉</div>
              <p>Loading events...</p>
            </div>
          ) : filtered.length === 0 ? (
            <div style={{ textAlign: 'center', padding: '4rem', color: 'rgba(255,255,255,0.5)' }}>
              <div style={{ fontSize: '3rem', marginBottom: '1rem' }}>😕</div>
              <p>No events found. Try a different search.</p>
            </div>
          ) : (
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))', gap: '1.5rem' }}>
              {filtered.map(event => (
                <div key={event._id} style={{
                  background: 'rgba(255,255,255,0.07)', backdropFilter: 'blur(20px)',
                  border: '1px solid rgba(255,255,255,0.12)', borderRadius: '16px',
                  overflow: 'hidden', transition: 'transform 0.3s, box-shadow 0.3s',
                  cursor: 'pointer'
                }}
                  onMouseEnter={e => { e.currentTarget.style.transform = 'translateY(-5px)'; e.currentTarget.style.boxShadow = '0 20px 40px rgba(124,58,237,0.3)'; }}
                  onMouseLeave={e => { e.currentTarget.style.transform = 'translateY(0)'; e.currentTarget.style.boxShadow = 'none'; }}
                >
                  <div style={{ position: 'relative' }}>
                    <img src={event.image || 'https://via.placeholder.com/400x220?text=Event'}
                      alt={event.name} style={{ width: '100%', height: '180px', objectFit: 'cover' }} />
                    <span style={{
                      position: 'absolute', top: '12px', left: '12px',
                      background: 'linear-gradient(135deg, #7c3aed, #a78bfa)',
                      color: 'white', padding: '4px 12px', borderRadius: '20px',
                      fontSize: '0.7rem', fontWeight: '700'
                    }}>{event.category}</span>
                    {event.availableSeats === 0 && (
                      <span style={{
                        position: 'absolute', top: '12px', right: '12px',
                        background: '#ef4444', color: 'white', padding: '4px 12px',
                        borderRadius: '20px', fontSize: '0.7rem', fontWeight: '700'
                      }}>SOLD OUT</span>
                    )}
                  </div>
                  <div style={{ padding: '1.2rem' }}>
                    <h3 style={{ color: 'white', fontWeight: '700', fontSize: '1rem', marginBottom: '0.5rem' }}>{event.name}</h3>
                    <p style={{ color: 'rgba(255,255,255,0.5)', fontSize: '0.8rem', marginBottom: '0.3rem' }}>
                      📅 {new Date(event.date).toLocaleDateString('en-IN', { day: 'numeric', month: 'short', year: 'numeric' })} • {event.time}
                    </p>
                    <p style={{ color: 'rgba(255,255,255,0.5)', fontSize: '0.8rem', marginBottom: '1rem' }}>📍 {event.venue}</p>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                      <span style={{ color: '#a78bfa', fontWeight: '800', fontSize: '1.1rem' }}>₹{event.price}</span>
                      <span style={{ color: 'rgba(255,255,255,0.4)', fontSize: '0.75rem' }}>{event.availableSeats} seats left</span>
                    </div>
                    <Link to={`/events/${event._id}`} style={{
                      display: 'block', marginTop: '1rem', textAlign: 'center',
                      background: event.availableSeats === 0 ? 'rgba(255,255,255,0.1)' : 'linear-gradient(135deg, #7c3aed, #a78bfa)',
                      color: event.availableSeats === 0 ? 'rgba(255,255,255,0.3)' : 'white',
                      padding: '10px', borderRadius: '10px', textDecoration: 'none',
                      fontWeight: '600', fontSize: '0.85rem',
                      pointerEvents: event.availableSeats === 0 ? 'none' : 'auto'
                    }}>
                      {event.availableSeats === 0 ? 'Sold Out' : 'Book Now 🎟️'}
                    </Link>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </section>
    </div>
  );
}
export default Home;
